compliant:
class Base {
public:
    virtual ~Base() = default;
};

class Derived : public Base {
public:
    void derivedMethod();
};

void processObject(Base* base) {
    // Compliant: safe downcast with runtime check
    if (Derived* derived = dynamic_cast<Derived*>(base)) {
        derived->derivedMethod(); // Safe: we know it's actually Derived
    }
}

// Alternative: using references
void processObjectRef(Base& base) {
    try {
        Derived& derived = dynamic_cast<Derived&>(base);
        derived.derivedMethod(); // Safe cast
    } catch (const std::bad_cast& e) {
        // Handle invalid cast
    }
}
